<!--
* @Author: zhangbo
* @Date: 2026/2/3 18:48
* @Descripttion: 适应 视频监控平台的 弹框
-->
<template>
  <LTPages
      :title="'弹框'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">适应 视频监控平台的 弹框。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <el-button @click="DialogLTMsg.isShow = true">弹框</el-button>
          <LTDialog
              v-if="DialogLTMsg.isShow"
              :DialogLTMsg="DialogLTMsg"
              @close="DialogLTMsg.isShow = false">
            <el-input v-model="DialogLTMsg.title"></el-input>
          </LTDialog>
        </div>
        <!--2、代码示例-->
        <div class="zhb-title">代码示例</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--4、DialogLTMsg配置参数-->
        <div class="zhb-title">DialogLTMsg配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="DialogLTMsgData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>

      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      mainCode: `<template>
    <el-button @click="DialogLTMsg.isShow = true">弹框</el-button>
       <LTDialog
           v-if="DialogLTMsg.isShow"
           :DialogLTMsg="DialogLTMsg"
           @close="DialogLTMsg.isShow = false">
       <el-input v-model="DialogLTMsg.title"></el-input>
    </LTDialog>
</template>`,
      jsCode: `export default {
  data() {
    return {
      DialogLTMsg: {
        isShow: false,
        title: '添加用户',
        showCloseBtn: true,
        styles: {
          width: '70%',
          height: '90%'
        }
      }
    }
  }
}`,
      DialogLTMsg: {
        isShow: false,
        title: '添加用户',
        showCloseBtn: true,
        styles: {
          width: '70%',
          height: '90%'
        }
      },
      // 配置参数
      tableData: [
        {
          text1:'DialogLTMsg',
          text2:'弹框信息',
          text3:'Obj',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@close',
          text2:'关闭回调',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'',
        }
      ],
      // DialogLTMsg配置参数
      DialogLTMsgData: [
        {
          text1:'isShow',
          text2:'是否开启',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'title',
          text2:'弹框名称',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'',
        },
        {
          text1:'showCloseBtn',
          text2:'是否展示自带的关闭按钮',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:'',
        },
        {
          text1:'styles',
          text2:'弹框样式',
          text3:'Obj',
          text4:'---',
          text5:'---',
          text6:'',
        }
      ],
    }
  }
}
</script>

